const styles = {
  Button: {
    borderRadius: '4px',
    cursor: 'pointer',
    zIndex: '2',
    pointerEvents: 'auto',
    position: 'absolute',
    bottom: '-39px',
    height: '29px',
    width: '29px',
    backgroundColor: '#fff',
    '&:hover': {
      backgroundColor: '#f5f5f5'
    }
  }
}
export default styles
